// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F';
  forecast: ForecastItem[];
}

export interface WeatherMainProps {
  city: string;
  temperature: number;
  condition: string;
  unit: string;
  icon: string;
}

export interface WeatherDetailsProps {
  humidity: number;
  windSpeed: number;
}

export interface ForecastStripProps {
  forecast: ForecastItem[];
  unit: string;
}

export interface ForecastDayProps {
  item: ForecastItem;
  unit: string;
}

export interface WeatherHookReturn {
  formattedTemp: string;
  unitLabel: string;
  conditionIcon: string;
  themeColors: {
    background: string;
    text: string;
    accent: string;
  };
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

