      accent: 'var(--color-cloudy-accent)',
    },
  },
  Rainy: {
    icon: '🌧️',
    colors: {
      background: 'var(--color-rainy-bg)',
      text: 'var(--color-rainy-text)',
      accent: 'var(--color-rainy-accent)',
    },
  },
  Snowy: {
    icon: '❄️',
    colors: {
      background: 'var(--color-snowy-bg)',
