export type WeatherConditionKey = keyof typeof WEATHER_THEMES;

export const CONDITION_FALLBACK = WEATHER_THEMES.Cloudy;

export const DAYS_OF_WEEK = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

/**
 * Mapping of prop condition strings to internal WEATHER_THEMES keys
 * Handles case-sensitivity and common variations
 */
export const CONDITION_MAP: Record<string, WeatherConditionKey> = {
  sunny: 'Sunny',
  sunnyDay: 'Sunny',
  cloudy: 'Cloudy',
  overcast: 'Cloudy',
  rainy: 'Rainy',
  rain: 'Rainy',
  snowy: 'Snowy',
  snow: 'Snowy',
  stormy: 'Stormy',
  storm: 'Stormy',
  clear: 'Clear',
  night: 'Clear',
};


// --- hooks.ts ---
import { useMemo } from 'react';
import { WeatherCardProps, WeatherHookReturn } from './types';

/**
 * Custom hook to transform raw weather data into display-ready formats.
 * @param props - Weather component properties
 * @returns Formatted strings and theme information
 */
export function useWeatherLogic(props: WeatherCardProps): WeatherHookReturn {
  const { temperature, unit = 'C', condition } = props;

  return useMemo(() => {
    // 1. Temperature & Unit Formatting
    // Round to nearest integer and append degree symbol
    const formattedTemp = `${Math.round(temperature)}°`;
    // Default to '°C' if unit is undefined, otherwise '°C' or '°F'
    const unitLabel = `°${unit}`;

    // 2. Condition Normalization
    const normalized = condition.toLowerCase();

    // 3. Condition Icon Selection and Theming Logic
    // Default values for unknown conditions
    let conditionIcon = '🌤️';
    let themeColors = {
      background: 'linear-gradient(135deg, #74b9ff 0%, #0984e3 100%)', // Default bright blue
      text: '#ffffff',
      accent: '#dff9fb',
    };

    // Mapping logic for icons and theme categories (Clear/Sunny, Cloudy/Overcast, Rainy/Stormy, Snowy)
    if (normalized.includes('sunny') || normalized.includes('clear')) {
      conditionIcon = '☀️';
      themeColors = {
        background: 'linear-gradient(135deg, #ff9f43 0%, #ff6b6b 100%)', // Warm oranges
        text: '#ffffff',
        accent: '#feca57',
      };
    } else if (normalized.includes('cloudy') || normalized.includes('overcast')) {
      conditionIcon = '☁️';
      themeColors = {
        background: 'linear-gradient(135deg, #bdc3c7 0%, #2c3e50 100%)', // Neutral/Gray tones
        text: '#ffffff',
        accent: '#ecf0f1',
      };
    } else if (normalized.includes('rain') || normalized.includes('storm')) {
      // Icon selection within the Rainy/Stormy category
      conditionIcon = normalized.includes('storm') ? '⛈️' : '🌧️';
      themeColors = {
        background: 'linear-gradient(135deg, #4834d4 0%, #130f40 100%)', // Deep blues/Indigos
        text: '#ffffff',
        accent: '#7ed6df',
      };
    } else if (normalized.includes('snow')) {
      conditionIcon = '❄️';
      themeColors = {
        background: 'linear-gradient(135deg, #ffffff 0%, #dff9fb 100%)', // Light cyans/Whites
        text: '#2f3542',
        accent: '#70a1ff',
      };
    }

    return {
      formattedTemp,
      unitLabel,
      conditionIcon,
      themeColors,
    };
  }, [temperature, unit, condition]);
}


