import React from 'react';
import { Stack, Heading, Box, Text, Image } from '@ggui-ai/design/primitives';
import type { WeatherMainProps } from '../types';

export function WeatherMain({
  city,
  temperature,
  condition,
  unit,
  icon,
}: WeatherMainProps) {
  // Simple heuristic to determine if icon is a URL or an emoji
  const isUrl = icon.startsWith('http') || icon.startsWith('/') || icon.includes('.');

  return (
    <Stack
      direction="vertical"
      align="center"
      gap={8}
      aria-live="polite"
    >
      <Heading level={2} color="var(--ggui-color-onSurface)">
        {city}
      </Heading>

      <Box
        aria-label={condition}
        style={{
          width: 80,
          height: 80,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        {isUrl ? (
          <Image
            src={icon}
            alt={condition}
            width={80}
            height={80}
            objectFit="contain"
          />
        ) : (
          <span style={{ fontSize: '64px', lineHeight: 1 }}>{icon}</span>
        )}
      </Box>

      <Heading
        level={1}
        style={{
          fontSize: 'var(--ggui-font-size-4xl, 72px)',
          color: 'var(--ggui-color-onSurface)',
          display: 'flex',
          alignItems: 'baseline',
          lineHeight: 1,
        }}
      >
        {temperature}
        <Text
          as="span"
          variant="bodyLarge"
          color="var(--ggui-color-onSurfaceVariant)"
          style={{ marginLeft: 'var(--ggui-spacing-1, 4px)' }}
        >
          {unit}
        </Text>
      </Heading>

      <Text
        variant="bodyLarge"
        weight="medium"
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {condition}
      </Text>
    </Stack>
  );
}


