import React from 'react';
import { Stack, Text, Divider, Box } from '@ggui-ai/design/primitives';
import type { WeatherDetailsProps } from '../types';

/**
 * WeatherDetails component displays humidity and wind speed in a horizontal row.
 * It uses a Stack layout with a vertical Divider between the two items.
 */
export function WeatherDetails({ humidity, windSpeed }: WeatherDetailsProps) {
  return (
    <Box paddingY="var(--ggui-spacing-4)">
      <Stack 
        direction="horizontal" 
        justify="between" 
        align="center"
      >
        {/* Humidity Detail Group */}
        <Stack gap={4} align="center">
          <Stack direction="horizontal" gap={8} align="center">
            <span role="img" aria-label="Humidity" aria-hidden="true" style={{ fontSize: '1.25rem' }}>
              💧
            </span>
            <Text 
              variant="body" 
              weight="semibold" 
              color="var(--ggui-color-onSurface)"
            >
              {humidity}%
            </Text>
          </Stack>
          <Text 
            variant="caption" 
            color="var(--ggui-color-onSurfaceVariant)"
          >
            Humidity
          </Text>
        </Stack>

        <Divider orientation="vertical" margin={16} />

        {/* Wind Speed Detail Group */}
        <Stack gap={4} align="center">
          <Stack direction="horizontal" gap={8} align="center">
            <span role="img" aria-label="Wind speed" aria-hidden="true" style={{ fontSize: '1.25rem' }}>
              🌬️
            </span>
            <Text 
              variant="body" 
              weight="semibold" 
              color="var(--ggui-color-onSurface)"
            >
              {windSpeed} km/h
            </Text>
          </Stack>
          <Text 
            variant="caption" 
            color="var(--ggui-color-onSurfaceVariant)"
          >
            Wind Speed
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
}


