import React from 'react';
import { Box, Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastDayProps } from '../types';

/**
 * ForecastDay renders an individual day's forecast.
 */
const ForecastDay = ({ item, unit }: ForecastDayProps) => {
  return (
    <Stack align="center" gap={4}>
      <Text 
        variant="label" 
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {item.day}
      </Text>
      <Text size="2xl">
        {item.icon}
      </Text>
      <Stack direction="horizontal" gap={8}>
        <Text weight="semibold">
          {item.high}°{unit}
        </Text>
        <Text 
          variant="caption" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {item.low}°{unit}
        </Text>
      </Stack>
    </Stack>
  );
};

/**
 * ForecastStrip displays a 5-day weather outlook as a strip.
 */
export const ForecastStrip = ({ forecast, unit }: ForecastStripProps) => {
  return (
    <Box
      padding={16}
      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
      style={{
        borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderBottomLeftRadius: 'var(--ggui-shape-radius-lg, 12px)',
        borderBottomRightRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="horizontal" justify="between">
        {forecast.map((item, index) => (
          <ForecastDay 
            key={`${item.day}-${index}`} 
            item={item} 
            unit={unit} 
          />
        ))}
      </Stack>
    </Box>
  );
};

export default ForecastStrip;


