import React from 'react';
import {
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Divider,
  Icon,
  Container,
} from '@ggui-ai/design/primitives';
import {
  WeatherCardProps,
  WeatherMainProps,
  WeatherDetailsProps,
  ForecastStripProps,
  ForecastDayProps,
} from './types';

const WeatherMain: React.FC<WeatherMainProps> = ({
  city,
  temperature,
  condition,
  unit,
  icon,
}) => (
  <Stack align="center" gap={4}>
    <Heading level={2} align="center">
      {city}
    </Heading>
    <Text size="4xl" weight="bold">
      {`${temperature}°${unit}`}
    </Text>
    <Stack direction="horizontal" align="center" gap={8}>
      <Text size="lg" color="var(--ggui-color-onSurfaceVariant)">
        {condition}
      </Text>
      <Text size="lg">{icon}</Text>
    </Stack>
  </Stack>
);

const WeatherDetails: React.FC<WeatherDetailsProps & { unit: string }> = ({
  humidity,
  windSpeed,
  unit,
}) => (
  <Box
    background="var(--ggui-color-surfaceVariant)"
    borderRadius="var(--ggui-shape-radius-lg)"
    padding={16}
  >
    <Stack direction="horizontal" justify="around" align="center">
      <Stack align="center" gap={2}>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Humidity
        </Text>
        <Text variant="bodyLarge" weight="semibold">
          {`${humidity}%`}
        </Text>
      </Stack>
      <Divider orientation="vertical" margin={16} />
      <Stack align="center" gap={2}>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Wind
        </Text>
        <Text variant="bodyLarge" weight="semibold">
          {`${windSpeed} ${unit === 'C' ? 'km/h' : 'mph'}`}
        </Text>
      </Stack>
    </Stack>
  </Box>
);

const ForecastDay: React.FC<ForecastDayProps> = ({ item, unit }) => (
  <Stack align="center" gap={8}>
    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
      {item.day}
    </Text>
    <Text size="lg">{item.icon}</Text>
    <Stack direction="horizontal" gap={4}>
      <Text weight="semibold">{`${item.high}°`}</Text>
      <Text color="var(--ggui-color-onSurfaceVariant)">{`${item.low}°`}</Text>
    </Stack>
  </Stack>
);

const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast, unit }) => (
  <Stack direction="horizontal" justify="between" gap={12} wrap>
    {forecast.map((item, index) => (
      <ForecastDay key={index} item={item} unit={unit} />
    ))}
  </Stack>
);

/**
 * Main WeatherCard component.
 */
const WeatherCard: React.FC<WeatherCardProps> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}) => {
  // Simple emoji mapping based on condition string (case-insensitive)
  const getIcon = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    return '⛅';
  };

  return (
    <Container maxWidth="sm">
      <Card padding={24} radius="xl" shadow="md">
        <Stack gap={24}>
          <WeatherMain
            city={city}
            temperature={temperature}
            condition={condition}
            unit={unit}
            icon={getIcon(condition)}
          />

          <WeatherDetails
            humidity={humidity}
            windSpeed={windSpeed}
            unit={unit}
          />

          <Stack gap={16}>
            <Divider orientation="horizontal" margin={0} />
            <ForecastStrip forecast={forecast} unit={unit} />
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
};

export default WeatherCard;


